import React from "react";
import Loading from "../components/Loading.gif";

const Spinner = () => {
  return (
    <div id="preloader" style={{display: "none"}}>
            <div id="loading-center">
                <div class="loader">
                </div>
            </div>
        </div>
  );
};

export default Spinner;
